/// Demonstrate performance characteristics of different table implementations
pub fn performance_comparison() {
    println!("\n=== Performance Comparison ===");

    let size = 1000;
    println!("Building tables with {size} entries...");

    // Build persistent table
    let start = std::time::Instant::now();
    let mut table_per = TableStPer::empty();
    for i in 0..size {
        table_per = table_per.insert(i, format!("value_{i}"), |_old, new| new.clone());
    }
    let per_time = start.elapsed();
    println!("Persistent table construction: {per_time:?}");

    // Build ephemeral table
    let start = std::time::Instant::now();
    let mut table_eph = TableStEph::empty();
    for i in 0..size {
        table_eph.insert(i, format!("value_{i}"), |_old, new| new.clone());
    }
    let eph_time = start.elapsed();
    println!("Ephemeral table construction: {eph_time:?}");

    // Build multi-threaded table
    let start = std::time::Instant::now();
    let mut table_mt = TableMtEph::empty();
    for i in 0..size {
        table_mt.insert(i, format!("value_{i}"), |_old, new| new.clone());
    }
    let mt_time = start.elapsed();
    println!("Multi-threaded table construction: {mt_time:?}");

    // Test map operation performance
    println!("\nMap operation performance:");

    let start = std::time::Instant::now();
    let _mapped_per = table_per.map(|s| s.to_uppercase());
    let per_map_time = start.elapsed();
    println!("Persistent map: {per_map_time:?}");

    let start = std::time::Instant::now();
    table_eph.map(|s| s.to_uppercase());
    let eph_map_time = start.elapsed();
    println!("Ephemeral map: {eph_map_time:?}");

    let start = std::time::Instant::now();
    table_mt.map(|s| s.to_uppercase());
    let mt_map_time = start.elapsed();
    println!("Multi-threaded map: {mt_map_time:?}");
}

fn find(&self, key: &K) -> (found: Option<V>)
    ensures
        match found {
            Some(v) => self@.contains_key(key@) && self@[key@] == v@,
            None => !self@.contains_key(key@),
        };

fn insert<F: Fn(&V, &V) -> V + Send + Sync + 'static>(&mut self, key: K, value: V, combine: F)
    ensures
        self@.contains_key(key@),
        self@.dom() =~= old(self)@.dom().insert(key@);

fn restrict(&mut self, keys: &ArraySetStEph<K>)
    requires keys@.finite()
    ensures self@.dom() =~= old(self)@.dom().intersect(keys@);

fn subtract(&mut self, keys: &ArraySetStEph<K>)
    requires keys@.finite()
    ensures self@.dom() =~= old(self)@.dom().difference(keys@);

fn size(&self) -> (count: usize)
    requires self.spec_tablesteph_wf()
    ensures count == self@.len();

fn singleton(key: K, value: V) -> (tree: Self)
    requires obeys_feq_clone::<Pair<K, V>>()
    ensures tree@ == Map::<K::V, V::V>::empty().insert(key@, value@);

fn tabulate<F: Fn(&K) -> V>(f: F, keys: &ArraySetStEph<K>) -> (tabulated: Self)
    requires forall|k: &K| f.requires((k,))
    ensures tabulated@.dom().finite();

fn map<F: Fn(&V) -> V>(&mut self, f: F)
    requires forall|v: &V| f.requires((v,)), obeys_feq_clone::<K>()
    ensures self@.dom() == old(self)@.dom();

fn filter<F: Fn(&K, &V) -> B>(&mut self, f: F)
    requires forall|k: &K, v: &V| f.requires((k, v)), obeys_feq_full::<Pair<K, V>>()
    ensures self@.dom().subset_of(old(self)@.dom());

fn intersection<F: Fn(&V, &V) -> V>(&mut self, other: &Self, combine: F)
    requires
        forall|v1: &V, v2: &V| combine.requires((v1, v2)),
        obeys_feq_clone::<K>(),
        obeys_view_eq::<K>(),
    ensures self@.dom() =~= old(self)@.dom().intersect(other@.dom());

fn difference(&mut self, other: &Self)
    requires obeys_feq_full::<Pair<K, V>>(), obeys_view_eq::<K>()
    ensures self@.dom() =~= old(self)@.dom().difference(other@.dom());

fn find(&self, key: &K) -> (found: Option<V>)
    requires self.spec_tablesteph_wf(), obeys_view_eq::<K>(), obeys_feq_full::<V>()
    ensures
        match found {
            Some(v) => self@.contains_key(key@) && self@[key@] == v@,
