fn intersection<F: Fn(&V, &V) -> V>(&self, other: &Self, combine: F) -> (common: Self)
    requires
        forall|v1: &V, v2: &V| combine.requires((v1, v2)),
        obeys_view_eq::<K>(),
        obeys_feq_full::<K>(),
    ensures common@.dom() =~= self@.dom().intersect(other@.dom());

fn difference(&self, other: &Self) -> (remaining: Self)
